import boto3

def lambda_handler(event, context):
    # Initialize AWS SDK
    s3 = boto3.client('s3')
    dynamodb = boto3.client('dynamodb')
    sns = boto3.client('sns')
    sqs = boto3.client('sqs')

    # Define shared IAM role for all Lambda functions
    iam_role = {
        'Version': '2012-10-17',
        'Statement': [
            {
                'Effect': 'Allow',
                'Action': 's3:*',
                'Resource': 'arn:aws:s3:::my-bucket/*'
            },
            {
                'Effect': 'Allow',
                'Action': 'dynamodb:*',
                'Resource': 'arn:aws:dynamodb:*'
            },
            {
                'Effect': 'Allow',
                'Action': 'sns:*',
                'Resource': 'arn:aws:sns:*'
            },
            {
                'Effect': 'Allow',
                'Action': 'sqs:*',
                'Resource': 'arn:aws:sqs:*'
            }
        ]
    }

    # Use shared IAM role for all Lambda functions
    lambda_function = boto3.client('lambda')
    response = lambda_function.create_function(
        FunctionName='my-function',
        Runtime='python3.8',
        Role=iam_role,
        Handler='index.handler',
        Code={
            'ZipFile': open('function.zip', 'rb').read()
        }
    )